Here's the result of running `cat -n` on a snippet of src/pages/CheckinPage.tsx
     1→import React, { useState, useEffect, useCallback, useMemo } from 'react';
     2→import {
     3→  CheckCircle, XCircle, RefreshCw, Phone, Calendar, Banknote,
     4→  AlertCircle, Edit3, Search, ChevronDown, User, MapPin,
     5→  Clock, CheckCircle2, Star
     6→} from 'lucide-react';
     7→import type { CheckinLead, StaffMember } from '../types';
     8→import { api } from '../api/client';
     9→
    10→interface Props {
    11→  currentUser: StaffMember;
    12→  onRefreshLeads: () => Promise<void>;
    13→  onEditLead?: (lead: CheckinLead) => void;
    14→  allUsers?: StaffMember[];
    15→}
    16→
    17→const MONTHS = ['янв','фев','мар','апр','май','июн','июл','авг','сен','окт','ноя','дек'];
    18→
    19→function fmtDate(raw: string): string {
    20→  const d = new Date(raw);
    21→  return `${d.getUTCDate()} ${MONTHS[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
    22→}
    23→
    24→function daysAgo(raw: string): string {
    25→  const todayMsk = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Moscow' }));
    26→  todayMsk.setHours(0, 0, 0, 0);
    27→  const date = new Date(raw);
    28→  const bookDay = new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()));
    29→  const diff = Math.floor((todayMsk.getTime() - bookDay.getTime()) / 86_400_000);
    30→  if (diff === 1) return 'вчера';
    31→  if (diff === 0) return 'сегодня';
    32→  if (diff <= 4) return `${diff} дня назад`;
    33→  return `${diff} дней назад`;
    34→}
    35→
    36→function fmtPhone(p: string): string {
    37→  if (!p) return '';
    38→  const d = p.replace(/\D/g, '');
    39→  if (d.length === 11) return `+7 (${d.slice(1,4)}) ${d.slice(4,7)}-${d.slice(7,9)}-${d.slice(9,11)}`;
    40→  return p;
    41→}
    42→
    43→function todayMsk(): string {
    44→  return new Date().toLocaleDateString('sv', { timeZone: 'Europe/Moscow' });
    45→}
    46→
    47→type YclientsFilter = 'all' | 'no_data' | 'waiting' | 'confirmed' | 'showed' | 'no_show_ycl';
    48→type DepositFilter  = 'all' | 'paid' | 'not_paid' | 'no_deposit';
    49→
    50→function yclientsLabel(att: number | null): { text: string; sub?: string; cls: string; dot: string } {
    51→  switch (att) {
    52→    case 1:  return { text: 'Пришёл', sub: 'данные Yclients', cls: 'bg-emerald-50 border-emerald-200 text-emerald-700', dot: 'bg-emerald-500' };
    53→    case -1: return { text: 'Не пришёл', sub: 'данные Yclients', cls: 'bg-rose-50 border-rose-200 text-rose-700', dot: 'bg-rose-500' };
    54→    case 0:  return { text: 'Ожидание клиента', cls: 'bg-amber-50 border-amber-200 text-amber-700', dot: 'bg-amber-400' };
    55→    case 2:  return { text: 'Подтвердил запись', cls: 'bg-indigo-50 border-indigo-200 text-indigo-700', dot: 'bg-indigo-500' };
    56→    default: return { text: 'Нет данных Yclients', cls: 'bg-neutral-50 border-neutral-200 text-neutral-400', dot: 'bg-neutral-300' };
    57→  }
    58→}
    59→
    60→export default function CheckinPage({ currentUser, onRefreshLeads, onEditLead, allUsers = [] }: Props) {
    61→  const [items, setItems]           = useState<CheckinLead[]>([]);
    62→  const [loading, setLoading]       = useState(true);
    63→  const [busy, setBusy]             = useState<Set<string>>(new Set());
    64→  const [dismissed, setDismissed]   = useState<Set<string>>(new Set());
    65→  const [fading, setFading]         = useState<Set<string>>(new Set());
    66→
    67→  const [searchInput, setSearchInput] = useState('');
    68→  const [search, setSearch]           = useState('');
    69→  const [managerFilter, setManagerFilter] = useState('all');
    70→  const [dateFrom, setDateFrom]       = useState('');
    71→  const [dateTo, setDateTo]           = useState('');
    72→  const [ycFilter, setYcFilter]       = useState<YclientsFilter>('all');
    73→  const [depFilter, setDepFilter]     = useState<DepositFilter>('all');
    74→
    75→  const isAdmin = currentUser.role === 'admin';
    76→
    77→  useEffect(() => {
    78→    const t = setTimeout(() => setSearch(searchInput), 200);
    79→    return () => clearTimeout(t);
    80→  }, [searchInput]);
    81→
    82→  const fetchItems = useCallback(async () => {
    83→    setLoading(true);
    84→    try {
    85→      const data = await api.checkin.list(currentUser.name, currentUser.role);
    86→      setItems(data);
    87→      setDismissed(new Set());
    88→      setFading(new Set());
    89→    } catch { /* ignore */ }
    90→    setLoading(false);
    91→  }, [currentUser.name, currentUser.role]);
    92→
    93→  useEffect(() => { fetchItems(); }, [fetchItems]);
    94→
    95→  const handleStatus = async (id: string, status: 'showed_up' | 'no_show') => {
    96→    setBusy(p => new Set(p).add(id));
    97→    try {
    98→      await api.checkin.quickUpdate(id, { status });
    99→      setFading(p => new Set(p).add(id));
   100→      setTimeout(() => {
   101→        setDismissed(p => new Set(p).add(id));
   102→        setFading(p => { const s = new Set(p); s.delete(id); return s; });
   103→      }, 500);
   104→      await onRefreshLeads();
   105→    } catch { /* ignore */ }
   106→    setBusy(p => { const s = new Set(p); s.delete(id); return s; });
   107→  };
   108→
   109→  const uniqueManagers = useMemo(() =>
   110→    Array.from(new Set(items.map(l => l.managerName).filter(Boolean))).sort(),
   111→    [items]
   112→  );
   113→
   114→  const filtered = useMemo(() => {
   115→    const term = search.toLowerCase();
   116→    return items.filter(l => {
   117→      if (dismissed.has(l.id ?? '')) return false;
   118→
   119→      if (term && !(
   120→        l.clientName.toLowerCase().includes(term) ||
   121→        (l.clientPhone && l.clientPhone.includes(term)) ||
   122→        (l.amocrmLeadId && l.amocrmLeadId.toLowerCase().includes(term))
   123→      )) return false;
   124→
   125→      if (managerFilter !== 'all' && l.managerName !== managerFilter) return false;
   126→
   127→      const bd = String(l.bookingDate).slice(0, 10);
   128→      if (dateFrom && bd < dateFrom) return false;
   129→      if (dateTo   && bd > dateTo)   return false;
   130→
   131→      if (ycFilter !== 'all') {
   132→        if (ycFilter === 'no_data'   && l.yclientsAttendance !== null)  return false;
   133→        if (ycFilter === 'waiting'   && l.yclientsAttendance !== 0)     return false;
   134→        if (ycFilter === 'confirmed' && l.yclientsAttendance !== 2)     return false;
   135→        if (ycFilter === 'showed'    && l.yclientsAttendance !== 1)     return false;
   136→        if (ycFilter === 'no_show_ycl' && l.yclientsAttendance !== -1) return false;
   137→      }
   138→
   139→      if (depFilter === 'paid'       && !(l.depositRequired && l.yookassaPaid)) return false;
   140→      if (depFilter === 'not_paid'   && !(l.depositRequired && !l.yookassaPaid)) return false;
   141→      if (depFilter === 'no_deposit' && l.depositRequired) return false;
   142→
   143→      return true;
   144→    });
   145→  }, [items, dismissed, search, managerFilter, dateFrom, dateTo, ycFilter, depFilter]);
   146→
   147→  const hasFilters = !!(search || searchInput || managerFilter !== 'all' || dateFrom || dateTo || ycFilter !== 'all' || depFilter !== 'all');
   148→
   149→  const resetFilters = () => {
   150→    setSearchInput(''); setSearch('');
   151→    setManagerFilter('all');
   152→    setDateFrom(''); setDateTo('');
   153→    setYcFilter('all');
   154→    setDepFilter('all');
   155→  };
   156→
   157→  const pendingCount = filtered.filter(l =>
   158→    l.yclientsAttendance !== 1 && l.yclientsAttendance !== -1
   159→  ).length;
   160→
   161→  if (loading) {
   162→    return (
   163→      <div className="flex items-center justify-center py-24">
   164→        <div className="w-6 h-6 border-2 border-indigo-600/30 border-t-indigo-600 rounded-full animate-spin" />
   165→      </div>
   166→    );
   167→  }
   168→
   169→  return (
   170→    <div className="space-y-5">
   171→
   172→      {/* Header */}
   173→      <div className="flex items-start justify-between gap-4">
   174→        <div>
   175→          <h2 className="text-sm font-display font-bold text-neutral-950 uppercase tracking-widest">
   176→            Проверка визитов
   177→          </h2>
   178→          <p className="text-[10px] text-neutral-400 font-bold uppercase tracking-widest mt-1">
   179→            {filtered.length === 0
   180→              ? 'Записей нет'
   181→              : `${filtered.length} ${filtered.length === 1 ? 'запись' : filtered.length < 5 ? 'записи' : 'записей'}`
   182→              + (pendingCount > 0 ? ` · ${pendingCount} ожидают подтверждения` : '')}
   183→          </p>
   184→        </div>
